48	    TraverseRoundQueue( RoundQueue: protocol.ar2es2Proto.IRoundInfo[] ) : protocol.ar2es2Proto.RoundInfo[]
49	    {
50	        let roundQueue: protocol.ar2es2Proto.RoundInfo[] = [];
51	        for ( let i = 0; i < RoundQueue.length; ++i )
52	        {
53	            let t = new protocol.ar2es2Proto.RoundInfo();
54	            let cur = RoundQueue[ i ];
55	
56	            t.PlateQueue = this.TraversePlateQueue( cur.PlateQueue );
57	            t.AwardTypeFlag = cur.AwardTypeFlag || 0;
58	            t.RoundWin = cur.RoundWin || 0;
59	            t.ReelWeightResult = cur.ReelWeightResult || 0;
60	            t.MaxFlag = cur.MaxFlag || false;
61	            t.CurrFeverGameType = cur.CurrFeverGameType || 0;
62	            t.NextFeverGameType = cur.NextFeverGameType || 0;
63	            t.FreeRemainRound = cur.FreeRemainRound || 0;
64	            t.FreeNowRound = cur.FreeNowRound || 0;
65	            t.FreeTotalRound = cur.FreeTotalRound || 0;
66	            t.MysteryEventKind = cur.MysteryEventKind || 0;
67	            t.NearMissKind = cur.NearMissKind || 0;
68	            t.NearMissStartCol = cur.NearMissStartCol || 0;
69	            t.PreScAccuStage = cur.PreScAccuStage || 0;
70	            t.PreScAccuCount = cur.PreScAccuCount || 0;
71	            t.ScAccuStage = cur.ScAccuStage || 0;
72	            t.ScAccuCount = cur.ScAccuCount || 0;
73	            t.ScAccuUpgrade = cur.ScAccuUpgrade ? this.TraverseScAccuUpgradeInfo( cur.ScAccuUpgrade ) : null;
74	            t.FreeGameExtraSpins = cur.FreeGameExtraSpins || 0;
75	            t.RespinLockedPos = cur.RespinLockedPos || [];
76	            t.WheelFeatures = this.TraverseFeatureResults( cur.WheelFeatures );
77	            t.WheelCount = cur.WheelCount || 0;
78	            t.PreGridFeature = this.TraverseGridColumns( cur.PreGridFeature );
79	            t.TransferResult = this.TraverseTransformInfos( cur.TransferResult );
80	            t.UpgradeResult = this.TraverseTransformInfos( cur.UpgradeResult );
81	
82	            roundQueue.push( t );
83	        }
84	        return roundQueue;
85	    }
